// src/pages/Budgets/components/BudgetForm.jsx

import { FaSave, FaWindowClose } from "react-icons/fa";
import React, { useEffect, useState } from "react";

import Button from "../../../components/Button/Button";
import MySelect from "../../../components/Select/MySelect";

const BudgetForm = ({
  initialData,
  onSave,
  onCancel,
  saving,
  categoryOptions,
}) => {
  const [formData, setFormData] = useState({
    name: "",
    amount: "",
    interval: "Month",
    start_date: "",
    categories: [],
    logo: "",
  });

  useEffect(() => {
    if (initialData) {
      let new_categories;
      new_categories = categoryOptions.filter((cat) =>
        initialData.categories.includes(cat.value)
      );
      setFormData({
        name: initialData.name || "",
        amount: initialData.amount || "",
        interval: initialData.interval || "Month",
        start_date: initialData.start_date || "",
        categories: new_categories || [],
        logo: initialData.logo || "",
      });
    } else {
      setFormData({
        name: "",
        amount: "",
        interval: "Month",
        start_date: "",
        categories: [],
        logo: "",
      });
    }
  }, [initialData, categoryOptions]);

  const handleSubmit = () => {
    if (!formData.name || !formData.amount || !formData.start_date) {
      alert("Please fill Name, Amount, and Start Date");
      return;
    }
    onSave(formData);
  };

  return (
    <div className="budget-dialog-content">
      <div className="input-group">
        <label>Budget Name</label>
        <input
          type="text"
          placeholder="e.g. Groceries"
          value={formData.name}
          onChange={(e) => setFormData({ ...formData, name: e.target.value })}
        />
      </div>

      <div className="input-group">
        <label>Amount (₹)</label>
        <input
          type="number"
          placeholder="0.00"
          value={formData.amount}
          onChange={(e) => setFormData({ ...formData, amount: e.target.value })}
        />
      </div>

      <div className="input-row">
        <div className="input-group">
          <label>Interval</label>
          <select
            value={formData.interval}
            onChange={(e) =>
              setFormData({ ...formData, interval: e.target.value })
            }
          >
            <option value="Month">Month</option>
          </select>
        </div>

        <div className="input-group">
          <label>Start Date</label>
          <input
            type="date"
            value={formData.start_date}
            onChange={(e) =>
              setFormData({ ...formData, start_date: e.target.value })
            }
          />
        </div>
      </div>

      <div className="input-group">
        <label>Categories (Select Multiple)</label>
        <MySelect
          isMulti
          options={categoryOptions}
          placeholder="Select Categories"
          value={formData.categories}
          onChange={(selected) =>
            setFormData({ ...formData, categories: selected })
          }
          isSearchable={true}
        />
      </div>

      <div className="input-group">
        <label>Logo URL (Optional)</label>
        <input
          type="text"
          placeholder="https://..."
          value={formData.logo}
          onChange={(e) => setFormData({ ...formData, logo: e.target.value })}
        />
      </div>

      <div className="budget-dialog-actions">
        <Button
          icon={<FaSave />}
          text="Save"
          variant="success"
          onClick={handleSubmit}
          disabled={saving}
        />
        <Button
          icon={<FaWindowClose />}
          text="Cancel"
          variant="warning"
          onClick={onCancel}
        />
      </div>
    </div>
  );
};

export default BudgetForm;
